UPDATE TB_CO_USER SET
    LSCHGDTM = SYSDATE
    , LSCHGID = #{ses.userId}
    , OFT_NM = #{DUTY_NM}
    , PZC_NM = #{POSITION_NM}
    , DWIN_TEL = DAMO.ENCRYPT_VAR_B64('EBILL_AES_256',  #{TEL_NUM},  '' )
    , REP_TEL = DAMO.ENCRYPT_VAR_B64('EBILL_AES_256',  #{TEL_NUM},  '' )
    , CUST_TEL = DAMO.ENCRYPT_VAR_B64('EBILL_AES_256',  #{TEL_NUM},  '' )
    , HP_NO = DAMO.ENCRYPT_VAR_B64('EBILL_AES_256',  #{CELL_NUM},  '' )
    , EMAIL = DAMO.ENCRYPT_VAR_B64('EBILL_AES_256',  #{EMAIL},  '' )
WHERE USER_ID = #{USER_ID}

